3	/// Fuzzy phrase matcher used to map STT transcripts to macro names.
4	///
5	/// Scoring is Levenshtein-similarity: `1.0 - (distance / max_char_len)`.
6	/// Only candidates scoring at or above the configured `threshold` are considered.
7	pub struct PhraseMatcher {
8	    threshold: f32,
9	}
10	
11	impl PhraseMatcher {
12	    /// Create a matcher with the given minimum similarity threshold (0.0–1.0).
13	    pub fn new(threshold: f32) -> Self {
14	        Self { threshold }
15	    }
16	
17	    /// Normalize a transcript or phrase for fuzzy comparison.
18	    ///
19	    /// Lowercases, strips punctuation, collapses whitespace.
20	    pub fn normalize(input: &str) -> String {
21	        input
22	            .to_lowercase()
23	            .trim()
24	            .chars()
25	            .filter(|c| c.is_alphanumeric() || c.is_whitespace())
26	            .collect::<String>()
27	            .split_whitespace()
28	            .collect::<Vec<_>>()
29	            .join(" ")
30	    }
31	
32	    /// Return the best-matching `(id, score)` from `candidates`, or `None` if no candidate
33	    /// scores at or above the threshold.
34	    ///
35	    /// `candidates` is an iterator of `(macro_id, phrase)` pairs.
36	    pub fn find_best_match<'a>(
37	        &self,
38	        input: &str,
39	        candidates: impl Iterator<Item = (&'a str, &'a str)>,
40	    ) -> Option<(&'a str, f32)> {
41	        let norm_input = Self::normalize(input);
42	        if norm_input.is_empty() {
43	            return None;
44	        }
45	
46	        let mut best_match = None;
47	        let mut best_score = 0.0;
48	
49	        for (id, phrase) in candidates {
50	            let norm_phrase = Self::normalize(phrase);
51	            if norm_phrase.is_empty() {
52	                continue;
53	            }
54	
55	            let max_len = norm_input.chars().count().max(norm_phrase.chars().count()) as f32;
56	            let dist = levenshtein(&norm_input, &norm_phrase) as f32;
57	            let score = if max_len > 0.0 {
58	                1.0 - (dist / max_len)
59	            } else {
60	                0.0
61	            };
62	
63	            if score >= self.threshold && score > best_score {
64	                best_score = score;
65	                best_match = Some((id, score));
66	            }
67	        }
68	
69	        best_match
70	    }
71	}
