44	/// Receives STT transcripts, finds the best-matching macro phrase, and fires the macro.
45	///
46	/// The dispatcher is shared across threads via `Arc` (see `SAFETY` comments below).
47	/// Live macro registry updates arrive through [`Dispatcher::update_macros`] without
48	/// restarting the pipeline.
49	pub struct Dispatcher {
50	    state: DispatcherState,
51	    matcher: PhraseMatcher,
52	    macros: Arc<RwLock<Vec<MacroConfig>>>,
53	    sound_player: Option<SoundPlayer>,
54	    macro_tx: Sender<MacroCmd>,
55	    default_dwell_ms: u64,
56	    default_gap_ms: u64,
57	}
58	
59	// SAFETY: rodio's OutputStream (held inside SoundPlayer) is !Send, but Dispatcher only ever
60	// accesses sound_player from the single thread that owns it. No reference to sound_player is
61	// shared across threads, so manual Send is sound.
62	unsafe impl Send for Dispatcher {}
63	// SAFETY: same invariant as Send — all access to sound_player is serialised through the single
64	// owning thread; no concurrent access can occur across thread boundaries.
65	unsafe impl Sync for Dispatcher {}
66	
67	impl Dispatcher {
68	    /// Create a new `Dispatcher`.
69	    ///
70	    /// `threshold` is the minimum fuzzy-match score (0.0–1.0) for a phrase to fire.
71	    /// `default_dwell_ms` and `default_gap_ms` are applied to key steps that omit their own timing.
72	    pub fn new(
73	        threshold: f32,
74	        macros: Vec<MacroConfig>,
75	        macro_tx: Sender<MacroCmd>,
76	        default_dwell_ms: u64,
77	        default_gap_ms: u64,
78	    ) -> Self {
79	        let sound_player = match SoundPlayer::new() {
80	            Ok(player) => Some(player),
81	            Err(e) => {
82	                tracing::warn!("Sound player disabled: {}", e);
83	                None
84	            }
85	        };
86	
87	        Self {
88	            state: DispatcherState::new(),
89	            matcher: PhraseMatcher::new(threshold),
90	            macros: Arc::new(RwLock::new(macros)),
91	            sound_player,
92	            macro_tx,
93	            default_dwell_ms,
94	            default_gap_ms,
95	        }
96	    }
97	
98	    /// Replace the live macro registry without restarting the pipeline.
99	    pub fn update_macros(&self, new_macros: Vec<MacroConfig>) {
100	        let mut macros = self.macros.write().unwrap();
101	        *macros = new_macros;
102	        tracing::info!("Registry updated with {} macros", macros.len());
103	    }
104	
105	    /// Return the number of macros currently registered.
106	    pub fn macro_count(&self) -> usize {
107	        self.macros.read().unwrap().len()
108	    }
109	
110	    fn check_condition(&self, if_flag: &Option<String>) -> bool {
111	        match if_flag {
112	            None => true,
113	            Some(if_flag) => {
114	                if let Some(stripped) = if_flag.strip_prefix('!') {
115	                    !self.state.get(stripped)
116	                } else {
117	                    self.state.get(if_flag.as_str())
118	                }
119	            }
120	        }
121	    }
122	
123	    /// Match `transcript` against the macro registry and fire the best-scoring macro.
124	    ///
125	    /// Returns [`DispatchOutcome::Fired`] when a phrase matches above the threshold,
126	    /// or [`DispatchOutcome::NoMatch`] otherwise. Side effects: plays an optional
127	    /// sound file and sends a [`MacroCmd`] to the input injector.
128	    pub fn process(&self, transcript: &str) -> DispatchOutcome {
129	        let macros = self.macros.read().unwrap();
130	        let candidates = macros
131	            .iter()
132	            .filter(|m| self.check_condition(&m.if_flag))
133	            .filter_map(|m| m.phrase.as_ref().map(|p| (m.name.as_str(), p.as_str())));
134	
135	        if let Some((best_match_name, score)) = self.matcher.find_best_match(transcript, candidates) {
136	            tracing::info!(macro_name = best_match_name, score, "Firing macro");
137	            if let Some(mac) = macros.iter().find(|m| m.name == best_match_name) {
138	                if let Some(sound_path) = &mac.sound {
139	                    if let Some(player) = &self.sound_player {
140	                        if let Err(e) = player.play(sound_path) {
141	                            tracing::error!("Failed to play sound for macro {}: {}", mac.name, e);
142	                        }
143	                    }
144	                }
145	
146	                let keys = mac.keys.iter().map(KeyStep::from_config).collect();
147	                let _ = self.macro_tx.send(MacroCmd::Execute {
148	                    keys,
149	                    default_dwell_ms: self.default_dwell_ms,
150	                    default_gap_ms: self.default_gap_ms,
151	                });
152	
153	                if let Some(set_flag) = &mac.set_flag {
154	                    if let Some(stripped) = set_flag.strip_prefix('!') {
155	                        self.state.set(stripped, false);
156	                    } else {
157	                        self.state.set(set_flag.as_str(), true);
158	                    }
159	                }
160	
161	                return DispatchOutcome::Fired {
162	                    macro_id: best_match_name.to_string(),
163	                    score,
164	                };
165	            }
166	        }
167	
168	        tracing::debug!(transcript, "No phrase matched above threshold");
169	        DispatchOutcome::NoMatch
170	    }
171	}
